// Writes to a PLAIN FILE, never process.env or n8n's canvas store --
// a long-running process's env snapshot isn't guaranteed to reflect a
// value written after startup. Downstream nodes (Carousel Builder) do
// a direct fs.readFileSync at execution time, always current, never
// dependent on n8n's in-memory state surviving a Git re-import.

const fs = require('fs');
const path = require('path');

if (!$json.access_token) {
  return [{ json: { rotated: false, reason: 'no_access_token_in_response' } }];
}

fs.writeFileSync(path.join('Shared', 'linkedin_token.txt'), $json.access_token, 'utf8');

return [{ json: { rotated: true, rotated_at: new Date().toISOString() } }];
